   308→    private void createClientCallbackHandler(Map<String, ?> configs) {
   309→        @SuppressWarnings("unchecked")
   310→        Class<? extends AuthenticateCallbackHandler> clazz = (Class<? extends AuthenticateCallbackHandler>) configs.get(SaslConfigs.SASL_CLIENT_CALLBACK_HANDLER_CLASS);
   311→        if (clazz == null)
   312→            clazz = clientCallbackHandlerClass();
