   317→    private void createServerCallbackHandlers(Map<String, ?> configs) {
   318→        for (String mechanism : jaasContexts.keySet()) {
   319→            AuthenticateCallbackHandler callbackHandler;
   320→            String prefix = ListenerName.saslMechanismPrefix(mechanism);
   321→            @SuppressWarnings("unchecked")
   322→            Class<? extends AuthenticateCallbackHandler> clazz =
   323→                    (Class<? extends AuthenticateCallbackHandler>) configs.get(prefix + BrokerSecurityConfigs.SASL_SERVER_CALLBACK_HANDLER_CLASS_CONFIG);
   324→            if (clazz != null)
   325→                callbackHandler = Utils.newInstance(clazz);
   326→            else if (mechanism.equals(PlainSaslServer.PLAIN_MECHANISM))
   327→                callbackHandler = new PlainServerCallbackHandler();
   328→            else if (ScramMechanism.isScram(mechanism))
   329→                callbackHandler = new ScramServerCallbackHandler(credentialCache.cache(mechanism, ScramCredential.class), tokenCache);
