   357→    private Class<? extends AuthenticateCallbackHandler> clientCallbackHandlerClass() {
   358→        switch (clientSaslMechanism) {
   359→            case SaslConfigs.GSSAPI_MECHANISM:
   360→                return KerberosClientCallbackHandler.class;
   361→            case OAuthBearerLoginModule.OAUTHBEARER_MECHANISM:
   362→                return OAuthBearerSaslClientCallbackHandler.class;
   363→            default:
