   368→    // As described in http://docs.oracle.com/javase/8/docs/technotes/guides/security/jgss/jgss-features.html:
   369→    // "To enable Java GSS to delegate to the native GSS library and its list of native mechanisms,
   370→    // set the system property "sun.security.jgss.native" to true"
   371→    // "In addition, when performing operations as a particular Subject, for example, Subject.doAs(...)
   372→    // or Subject.doAsPrivileged(...), the to-be-used GSSCredential should be added to Subject's
   373→    // private credential set. Otherwise, the GSS operations will fail since no credential is found."
   374→    private void maybeAddNativeGssapiCredentials(Subject subject) {
   375→        boolean usingNativeJgss = Boolean.getBoolean(GSS_NATIVE_PROP);
   376→        if (usingNativeJgss && subject.getPrivateCredentials(GSSCredential.class).isEmpty()) {
   377→
   378→            final String servicePrincipal = SaslClientAuthenticator.firstPrincipal(subject);
   379→            KerberosName kerberosName;
   380→            try {
   381→                kerberosName = KerberosName.parse(servicePrincipal);
   382→            } catch (IllegalArgumentException e) {
   383→                throw new KafkaException("Principal has name with unexpected format " + servicePrincipal);
   384→            }
   385→            final String servicePrincipalName = kerberosName.serviceName();
   386→            final String serviceHostname = kerberosName.hostName();
   387→
   388→            try {
   389→                GSSManager manager = gssManager();
   390→                // This Oid is used to represent the Kerberos version 5 GSS-API mechanism. It is defined in
   391→                // RFC 1964.
   392→                Oid krb5Mechanism = new Oid("1.2.840.113554.1.2.2");
   393→                GSSName gssName = manager.createName(servicePrincipalName + "@" + serviceHostname, GSSName.NT_HOSTBASED_SERVICE);
   394→                GSSCredential cred = manager.createCredential(gssName,
   395→                        GSSContext.INDEFINITE_LIFETIME, krb5Mechanism, GSSCredential.ACCEPT_ONLY);
   396→                subject.getPrivateCredentials().add(cred);
   397→                log.info("Configured native GSSAPI private credentials for {}@{}", serviceHostname, serviceHostname);
   398→            } catch (GSSException ex) {
   399→                log.warn("Cannot add private credential to subject; clients authentication may fail", ex);
   400→            }
   401→        }
   402→    }
