   151→    public SaslServerAuthenticator(Map<String, ?> configs,
   152→                                   Map<String, AuthenticateCallbackHandler> callbackHandlers,
   153→                                   String connectionId,
   154→                                   Map<String, Subject> subjects,
   155→                                   KerberosShortNamer kerberosNameParser,
   156→                                   ListenerName listenerName,
   157→                                   SecurityProtocol securityProtocol,
   158→                                   TransportLayer transportLayer,
   159→                                   Map<String, Long> connectionsMaxReauthMsByMechanism,
   160→                                   ChannelMetadataRegistry metadataRegistry,
   161→                                   Time time,
   162→                                   Function<Short, ApiVersionsResponse> apiVersionSupplier) {
   163→        this.callbackHandlers = callbackHandlers;
   164→        this.connectionId = connectionId;
   165→        this.subjects = subjects;
   166→        this.listenerName = listenerName;
   167→        this.securityProtocol = securityProtocol;
   168→        this.enableKafkaSaslAuthenticateHeaders = false;
   169→        this.transportLayer = transportLayer;
   170→        this.connectionsMaxReauthMsByMechanism = connectionsMaxReauthMsByMechanism;
   171→        this.time = time;
   172→        this.reauthInfo = new ReauthInfo();
   173→        this.metadataRegistry = metadataRegistry;
   174→        this.apiVersionSupplier = apiVersionSupplier;
   175→
   176→        this.configs = configs;
   177→        @SuppressWarnings("unchecked")
   178→        List<String> enabledMechanisms = (List<String>) this.configs.get(BrokerSecurityConfigs.SASL_ENABLED_MECHANISMS_CONFIG);
   179→        if (enabledMechanisms == null || enabledMechanisms.isEmpty())
   180→            throw new IllegalArgumentException("No SASL mechanisms are enabled");
   181→        this.enabledMechanisms = new ArrayList<>(new HashSet<>(enabledMechanisms));
   182→        for (String mechanism : this.enabledMechanisms) {
   183→            if (!callbackHandlers.containsKey(mechanism))
   184→                throw new IllegalArgumentException("Callback handler not specified for SASL mechanism " + mechanism);
   185→            if (!subjects.containsKey(mechanism))
   186→                throw new IllegalArgumentException("Subject cannot be null for SASL mechanism " + mechanism);
   187→            LOG.trace("{} for mechanism={}: {}", BrokerSecurityConfigs.CONNECTIONS_MAX_REAUTH_MS_CONFIG, mechanism,
   188→                    connectionsMaxReauthMsByMechanism.get(mechanism));
   189→        }
   190→
   191→        // Note that the old principal builder does not support SASL, so we do not need to pass the
   192→        // authenticator or the transport layer
   193→        this.principalBuilder = ChannelBuilders.createPrincipalBuilder(configs, kerberosNameParser, null);
   194→
   195→        saslAuthRequestMaxReceiveSize = (Integer) configs.get(BrokerSecurityConfigs.SASL_SERVER_MAX_RECEIVE_SIZE_CONFIG);
   196→        if (saslAuthRequestMaxReceiveSize == null)
   197→            saslAuthRequestMaxReceiveSize = BrokerSecurityConfigs.DEFAULT_SASL_SERVER_MAX_RECEIVE_SIZE;
   198→    }
