   200→    private void createSaslServer(String mechanism) throws IOException {
   201→        this.saslMechanism = mechanism;
   202→        Subject subject = subjects.get(mechanism);
   203→        final AuthenticateCallbackHandler callbackHandler = callbackHandlers.get(mechanism);
   204→        if (mechanism.equals(SaslConfigs.GSSAPI_MECHANISM)) {
   205→            saslServer = createSaslKerberosServer(callbackHandler, configs, subject);
   206→        } else {
   207→            try {
   208→                saslServer = SecurityManagerCompatibility.get().callAs(subject, () ->
   209→                    Sasl.createSaslServer(saslMechanism, "kafka", serverAddress().getHostName(), configs, callbackHandler));
   210→                if (saslServer == null) {
   211→                    throw new SaslException("Kafka Server failed to create a SaslServer to interact with a client during session authentication with server mechanism " + saslMechanism);
   212→                }
   213→            } catch (CompletionException e) {
   214→                throw new SaslException("Kafka Server failed to create a SaslServer to interact with a client during session authentication with server mechanism " + saslMechanism, e.getCause());
   215→            }
   216→        }
   217→    }
